# -*- coding: utf-8 -*-
# File: models/stock_checker.py
# Purpose: Core helper model providing all stock data computation methods
#          used by the Stock Enhanced Checker OWL dashboard.

import logging
from odoo import models, fields, api

_logger = logging.getLogger(__name__)


class StockCheckerHelper(models.TransientModel):
    """
    Transient helper model for the Stock Enhanced Checker dashboard.
    Exposes RPC-callable methods that aggregate stock, reservation,
    and incoming quantities per product/location.
    """
    _name = 'stock.checker.helper'
    _description = 'Stock Checker Helper'

    @api.model
    def get_warehouses(self):
        """
        Return all active warehouses as a list of dicts.

        :return: list of {'id': int, 'name': str, 'lot_stock_id': int}
        """
        warehouses = self.env['stock.warehouse'].search([('active', '=', True)])
        return [
            {
                'id': wh.id,
                'name': wh.name,
                'lot_stock_id': wh.lot_stock_id.id if wh.lot_stock_id else False,
            }
            for wh in warehouses
        ]

    @api.model
    def get_locations(self, warehouse_id):
        """
        Return all internal locations that are children of the given warehouse's
        main stock location.

        :param warehouse_id: int, ID of the stock.warehouse record
        :return: list of {'id': int, 'name': str, 'complete_name': str}
        """
        if not warehouse_id:
            return []

        warehouse = self.env['stock.warehouse'].browse(warehouse_id)
        if not warehouse.exists():
            return []

        parent_location = warehouse.lot_stock_id
        # Search for all internal child locations (recursive via child_of)
        locations = self.env['stock.location'].search([
            ('id', 'child_of', parent_location.id),
            ('usage', '=', 'internal'),
            ('active', '=', True),
        ])
        return [
            {
                'id': loc.id,
                'name': loc.name,
                'complete_name': loc.complete_name,
            }
            for loc in locations
        ]

    @api.model
    def get_stock_data(self, location_id, search='', filter_type='all', offset=0, limit=50):
        """
        Fetch paginated product stock data for the given location.

        Quantities computed:
          - qty_on_hand: sum of stock.quant.quantity at location
          - qty_reserved: sum of reserved_qty from outgoing stock.move.line at location
          - actual_available: qty_on_hand - qty_reserved
          - incoming_qty: sum of (product_qty - qty_received) from confirmed PO lines

        :param location_id: int, ID of stock.location
        :param search: str, search term for product name or internal reference
        :param filter_type: str, one of 'all', 'in_stock', 'out_of_stock', 'low_stock'
        :param offset: int, pagination offset
        :param limit: int, number of records per page
        :return: dict with 'products' list and 'total' count
        """
        if not location_id:
            return {'products': [], 'total': 0}

        location = self.env['stock.location'].browse(location_id)
        if not location.exists():
            return {'products': [], 'total': 0}

        # Get low stock threshold from config
        low_stock_threshold = int(
            self.env['ir.config_parameter'].sudo().get_param(
                'stock_enhanced_checker.low_stock_threshold', '5'
            )
        )

        # Get all child locations (inclusive)
        child_location_ids = self.env['stock.location'].search([
            ('id', 'child_of', location_id),
            ('usage', '=', 'internal'),
            ('active', '=', True),
        ]).ids

        if not child_location_ids:
            child_location_ids = [location_id]

        # ── 1. On-hand quantities from stock.quant ──────────────────────────
        quant_domain = [
            ('location_id', 'in', child_location_ids),
            ('quantity', '>', 0),
        ]
        quants = self.env['stock.quant'].read_group(
            quant_domain,
            fields=['product_id', 'quantity:sum'],
            groupby=['product_id'],
        )
        qty_on_hand_map = {q['product_id'][0]: q['quantity'] for q in quants}

        # ── 2. Reserved quantities from outgoing stock.move.line ────────────
        reserved_domain = [
            ('location_id', 'in', child_location_ids),
            ('state', 'in', ('partially_available', 'assigned')),
            ('quantity', '>', 0),
        ]
        reserved_lines = self.env['stock.move.line'].read_group(
            reserved_domain,
            fields=['product_id', 'quantity:sum'],
            groupby=['product_id'],
        )
        qty_reserved_map = {r['product_id'][0]: r['quantity'] for r in reserved_lines}

        # ── 3. Incoming from confirmed Purchase Orders ──────────────────────
        # Search all confirmed PO lines; filter in Python for qty_received < product_qty
        po_lines = self.env['purchase.order.line'].search([
            ('order_id.state', '=', 'purchase'),
        ])
        incoming_map = {}
        po_refs_map = {}
        for line in po_lines:
            if line.qty_received < line.product_qty:
                pid = line.product_id.id
                pending = line.product_qty - line.qty_received
                incoming_map[pid] = incoming_map.get(pid, 0.0) + pending
                po_name = line.order_id.name
                if pid not in po_refs_map:
                    po_refs_map[pid] = []
                if po_name not in po_refs_map[pid]:
                    po_refs_map[pid].append(po_name)

        # ── 4. Reorder points ───────────────────────────────────────────────
        orderpoints = self.env['stock.warehouse.orderpoint'].search([
            ('location_id', 'in', child_location_ids),
        ])
        reorder_map = {}
        for op in orderpoints:
            pid = op.product_id.id
            if pid not in reorder_map:
                reorder_map[pid] = op.product_min_qty

        # ── 5. Build product pool ───────────────────────────────────────────
        all_product_ids = set(qty_on_hand_map.keys())

        # Build product domain for search
        product_domain = [
            ('id', 'in', list(all_product_ids)),
            ('active', '=', True),
        ]
        if search:
            product_domain += ['|',
                ('name', 'ilike', search),
                ('default_code', 'ilike', search),
            ]

        products = self.env['product.product'].search(product_domain)

        # ── 6. Apply filter ─────────────────────────────────────────────────
        result = []
        for prod in products:
            pid = prod.id
            on_hand = qty_on_hand_map.get(pid, 0.0)
            reserved = qty_reserved_map.get(pid, 0.0)
            actual_available = on_hand - reserved
            incoming = incoming_map.get(pid, 0.0)
            reorder_point = reorder_map.get(pid, 0.0)

            # Apply filter_type
            if filter_type == 'in_stock' and actual_available <= 0:
                continue
            if filter_type == 'out_of_stock' and actual_available > 0:
                continue
            if filter_type == 'low_stock' and not (0 < actual_available <= low_stock_threshold):
                continue

            result.append({
                'id': pid,
                'name': prod.display_name,
                'default_code': prod.default_code or '',
                'uom_name': prod.uom_id.name if prod.uom_id else '',
                'qty_on_hand': round(on_hand, 3),
                'qty_reserved': round(reserved, 3),
                'actual_available': round(actual_available, 3),
                'incoming_qty': round(incoming, 3),
                'po_refs': ', '.join(po_refs_map.get(pid, [])),
                'reorder_point': round(reorder_point, 3),
                'list_price': prod.list_price,
                'low_stock_threshold': low_stock_threshold,
            })

        # Sort: negative available first, then by name
        result.sort(key=lambda x: (x['actual_available'] >= 0, x['name']))

        total = len(result)
        paginated = result[offset: offset + limit]
        return {'products': paginated, 'total': total}

    @api.model
    def search_partner(self, query, limit=10):
        """
        Search partners by partner_code (from buz_partner_code_auto) or name.
        Used by the partner code autocomplete in the Stock Checker dashboard.

        :param query: str, search term
        :param limit: int, max results
        :return: list of {'id', 'name', 'partner_code', 'display'}
        """
        if not query or not query.strip():
            return []
        domain = [
            '|',
            ('partner_code', 'ilike', query.strip()),
            ('name', 'ilike', query.strip()),
        ]
        partners = self.env['res.partner'].search(domain, limit=limit)
        return [
            {
                'id': p.id,
                'name': p.name,
                'ref': p.partner_code or '',       # send as 'ref' so frontend stays unchanged
                'display': f'[{p.partner_code}] {p.name}' if p.partner_code else p.name,
            }
            for p in partners
        ]

    @api.model
    def create_quotation(self, lines, partner_id=None, partner_name=None):
        """
        Create a Sale Order (quotation) with the given product lines and partner.

        Partner resolution order:
          1. partner_id provided → use existing partner
          2. partner_name provided (no partner_id) → create new res.partner
          3. Neither → fallback to current user's partner

        :param lines: list of {'product_id': int, 'qty': float, 'price': float}
        :param partner_id: int or None — existing partner ID
        :param partner_name: str or None — name for a new partner
        :return: dict with 'sale_order_id' and 'name', or 'error' key on failure
        """
        if not lines:
            return {'error': 'No products selected'}

        try:
            SaleOrder = self.env['sale.order']
            SaleOrderLine = self.env['sale.order.line']
            Partner = self.env['res.partner']

            # ── Resolve partner ──────────────────────────────────────────
            if partner_id:
                partner = Partner.browse(int(partner_id))
                if not partner.exists():
                    _logger.warning(
                        'stock_enhanced_checker: partner_id=%s not found, falling back',
                        partner_id,
                    )
                    partner_id = self.env.user.partner_id.id
                else:
                    partner_id = partner.id
            elif partner_name and partner_name.strip():
                # Create new partner on-the-fly
                new_partner = Partner.create({'name': partner_name.strip()})
                partner_id = new_partner.id
                _logger.info(
                    'stock_enhanced_checker: created new partner "%s" id=%s',
                    partner_name.strip(), partner_id,
                )
            else:
                # Fallback: current user's partner
                partner_id = self.env.user.partner_id.id

            # ── Create Sale Order ────────────────────────────────────────
            order = SaleOrder.create({
                'partner_id': partner_id,
            })

            for line in lines:
                product = self.env['product.product'].browse(line.get('product_id'))
                if not product.exists():
                    _logger.warning(
                        'stock_enhanced_checker: skipping unknown product_id=%s',
                        line.get('product_id'),
                    )
                    continue

                SaleOrderLine.create({
                    'order_id': order.id,
                    'product_id': product.id,
                    'product_uom_qty': float(line.get('qty', 1.0)),
                    'price_unit': float(line.get('price', product.list_price)),
                    'product_uom': product.uom_id.id,
                })

            return {
                'sale_order_id': order.id,
                'name': order.name,
            }

        except Exception as exc:
            _logger.exception('stock_enhanced_checker: create_quotation failed')
            return {'error': str(exc)}

    @api.model
    def get_user_preferences(self):
        """
        Return stored warehouse/location preferences for the current user.

        :return: dict with 'warehouse_id' and 'location_id'
        """
        uid = str(self.env.uid)
        param_wh = self.env['ir.config_parameter'].sudo().get_param(
            f'stock_enhanced_checker.user_{uid}_warehouse_id'
        )
        param_loc = self.env['ir.config_parameter'].sudo().get_param(
            f'stock_enhanced_checker.user_{uid}_location_id'
        )
        return {
            'warehouse_id': int(param_wh) if param_wh else False,
            'location_id': int(param_loc) if param_loc else False,
        }

    @api.model
    def save_user_preferences(self, warehouse_id, location_id):
        """
        Persist warehouse/location selection for the current user.

        :param warehouse_id: int
        :param location_id: int
        :return: bool True on success
        """
        uid = str(self.env.uid)
        ICP = self.env['ir.config_parameter'].sudo()
        if warehouse_id:
            ICP.set_param(f'stock_enhanced_checker.user_{uid}_warehouse_id', str(warehouse_id))
        if location_id:
            ICP.set_param(f'stock_enhanced_checker.user_{uid}_location_id', str(location_id))
        return True

/** @odoo-module **/
/**
 * File: static/src/js/stock_checker_action.js
 * Purpose: Main OWL component for the Stock Enhanced Checker client action.
 *          Handles all state management: warehouse/location selection,
 *          product loading, search/filter, multi-select, and quotation creation.
 */

import { Component, useState, onWillStart, onWillUpdateProps } from "@odoo/owl";
import { registry } from "@web/core/registry";
import { useService } from "@web/core/utils/hooks";
import { _t } from "@web/core/l10n/translation";
import { StockCheckerTable } from "./stock_checker_table";
import { STOCK_FILTERS, debounce, formatQty } from "./stock_checker_filters";

/**
 * StockCheckerAction
 *
 * Root OWL component registered as the "stock_enhanced_checker.StockCheckerAction"
 * client action tag. Manages the complete stock checker dashboard lifecycle.
 */
class StockCheckerAction extends Component {
    static template = "stock_enhanced_checker.StockCheckerAction";
    static components = { StockCheckerTable };

    // ── Lifecycle ──────────────────────────────────────────────────────────

    setup() {
        this.orm = useService("orm");
        this.action = useService("action");
        this.notification = useService("notification");

        /** @type {string[]} */
        this.filters = STOCK_FILTERS;

        /** @type {ReturnType<typeof useState>} */
        this.state = useState({
            // Warehouse & location
            warehouses: [],
            locations: [],
            selectedWarehouseId: false,
            selectedLocationId: false,

            // Product data
            products: [],
            total: 0,
            offset: 0,
            limit: 50,

            // UI
            loading: false,
            creating: false,
            search: '',
            filterType: 'all',
            toast: null,

            // Selection
            selectedIds: [],
            qtys: {},      // { productId: qty }
            prices: {},    // { productId: price }

            // Partner
            partnerCode: '',
            partnerName: '',
            selectedPartnerId: false,
            partnerResults: [],
        });

        /** Debounced partner code search */
        this._debouncedPartnerSearch = debounce(this._searchPartner.bind(this), 300);
        this._debouncedSearch = null;

        onWillStart(async () => {
            await this._init();
        });
    }

    // ── Init ───────────────────────────────────────────────────────────────

    /**
     * Initialise the component: load warehouses and restore user preferences.
     */
    async _init() {
        this.state.loading = true;
        try {
            // Load warehouses and user prefs in parallel
            const [warehouses, prefs] = await Promise.all([
                this.orm.call('stock.checker.helper', 'get_warehouses', []),
                this.orm.call('stock.checker.helper', 'get_user_preferences', []),
            ]);

            this.state.warehouses = warehouses;

            // Restore or default warehouse
            let warehouseId = prefs.warehouse_id;
            if (!warehouseId && warehouses.length) {
                warehouseId = warehouses[0].id;
            }

            if (warehouseId) {
                this.state.selectedWarehouseId = warehouseId;
                await this._loadLocations(warehouseId);

                // Restore or default location
                let locationId = prefs.location_id;
                if (!locationId && this.state.locations.length) {
                    locationId = this.state.locations[0].id;
                }

                if (locationId) {
                    this.state.selectedLocationId = locationId;
                    await this._loadStockData(true);
                }
            }
        } finally {
            this.state.loading = false;
        }
    }

    // ── Data Loaders ───────────────────────────────────────────────────────

    /**
     * Load internal locations for a given warehouse.
     * @param {number} warehouseId
     */
    async _loadLocations(warehouseId) {
        const locs = await this.orm.call(
            'stock.checker.helper', 'get_locations', [], { warehouse_id: warehouseId }
        );
        this.state.locations = locs;
    }

    /**
     * Load (or reload) stock data for the current location/filter/search.
     * @param {boolean} reset - If true, reset offset and product list
     */
    async _loadStockData(reset = false) {
        if (!this.state.selectedLocationId) return;

        if (reset) {
            this.state.offset = 0;
            this.state.products = [];
        }

        this.state.loading = true;
        try {
            const result = await this.orm.call(
                'stock.checker.helper', 'get_stock_data', [],
                {
                    location_id: this.state.selectedLocationId,
                    search: this.state.search,
                    filter_type: this.state.filterType,
                    offset: this.state.offset,
                    limit: this.state.limit,
                }
            );

            if (reset) {
                this.state.products = result.products;
            } else {
                this.state.products = [...this.state.products, ...result.products];
            }
            this.state.total = result.total;
        } catch (err) {
            this._showToast('error', _t('Error'), _t('Failed to load stock data.'));
            console.error('[StockChecker] get_stock_data error:', err);
        } finally {
            this.state.loading = false;
        }
    }

    // ── Public methods (bound to template events) ──────────────────────────

    /**
     * Expose public loadStockData for refresh button.
     */
    async loadStockData() {
        await this._loadStockData(true);
    }

    /**
     * Handle warehouse dropdown change.
     * @param {Event} ev
     */
    async onWarehouseChange(ev) {
        const warehouseId = parseInt(ev.target.value) || false;
        this.state.selectedWarehouseId = warehouseId;
        this.state.selectedLocationId = false;
        this.state.products = [];
        this.state.total = 0;

        if (warehouseId) {
            await this._loadLocations(warehouseId);
            // Auto-select the first location (warehouse default stock)
            if (this.state.locations.length) {
                this.state.selectedLocationId = this.state.locations[0].id;
                await this._loadStockData(true);
                this._savePreferences();
            }
        } else {
            this.state.locations = [];
        }
    }

    /**
     * Handle location dropdown change.
     * @param {Event} ev
     */
    async onLocationChange(ev) {
        const locationId = parseInt(ev.target.value) || false;
        this.state.selectedLocationId = locationId;
        this.state.products = [];
        this.state.selectedIds = [];
        this.state.qtys = {};
        this.state.prices = {};

        if (locationId) {
            await this._loadStockData(true);
            this._savePreferences();
        }
    }

    // ── Partner Search ───────────────────────────────────────────────────────

    /**
     * Handle partner code input — update state and trigger debounced RPC search.
     * @param {InputEvent} ev
     */
    onPartnerCodeInput(ev) {
        this.state.partnerCode = ev.target.value;
        this.state.selectedPartnerId = false;
        if (!ev.target.value.trim()) {
            this.state.partnerResults = [];
            return;
        }
        this._debouncedPartnerSearch();
    }

    /**
     * Close the partner dropdown on Escape key.
     * @param {KeyboardEvent} ev
     */
    onPartnerCodeKeydown(ev) {
        if (ev.key === 'Escape') {
            this.state.partnerResults = [];
        }
    }

    /**
     * Execute partner search RPC (called after debounce delay).
     */
    async _searchPartner() {
        const q = this.state.partnerCode;
        if (!q || !q.trim()) {
            this.state.partnerResults = [];
            return;
        }
        try {
            const results = await this.orm.call(
                'stock.checker.helper', 'search_partner', [],
                { query: q, limit: 8 }
            );
            this.state.partnerResults = results;
        } catch (err) {
            console.error('[StockChecker] search_partner error:', err);
        }
    }

    /**
     * Select a partner from the autocomplete dropdown.
     * @param {{ id: number, name: string, ref: string, display: string }} partner
     */
    onSelectPartner(partner) {
        this.state.selectedPartnerId = partner.id;
        this.state.partnerCode = partner.ref || partner.display;
        this.state.partnerName = partner.name;
        this.state.partnerResults = [];
    }

    /**
     * Handle customer name input — clears selected partner since user may be
     * typing a new (non-existing) customer name.
     * @param {InputEvent} ev
     */
    onPartnerNameInput(ev) {
        this.state.partnerName = ev.target.value;
        this.state.selectedPartnerId = false;
    }

    /**
     * Handle search input typing — update local state only, no RPC.
     * The actual search fires when the user presses Enter.
     * @param {InputEvent} ev
     */
    onSearchType(ev) {
        this.state.search = ev.target.value;
    }

    /**
     * Handle search keydown — trigger load only when Enter is pressed.
     * @param {KeyboardEvent} ev
     */
    async onSearchKeydown(ev) {
        if (ev.key === 'Enter') {
            await this._loadStockData(true);
        }
    }

    /**
     * Handle filter pill click.
     * @param {string} filterKey
     */
    async onFilterChange(filterKey) {
        this.state.filterType = filterKey;
        await this._loadStockData(true);
    }

    /**
     * Load the next page of products.
     */
    async loadMore() {
        this.state.offset += this.state.limit;
        await this._loadStockData(false);
    }

    // ── Selection ──────────────────────────────────────────────────────────

    /**
     * Toggle all products' selection state.
     */
    onToggleAll() {
        if (this.allSelected) {
            this.state.selectedIds = [];
        } else {
            const newIds = [...this.state.selectedIds];
            const newQtys = { ...this.state.qtys };
            const newPrices = { ...this.state.prices };

            for (const p of this.state.products) {
                if (!newIds.includes(p.id)) {
                    newIds.push(p.id);
                    // Auto-fill qty with 1 as default
                    newQtys[p.id] = 1;
                    newPrices[p.id] = p.list_price;
                }
            }
            this.state.selectedIds = newIds;
            this.state.qtys = newQtys;
            this.state.prices = newPrices;
        }
    }

    /**
     * Toggle individual product row selection.
     * @param {number} productId
     */
    onToggleRow(productId) {
        const idx = this.state.selectedIds.indexOf(productId);
        if (idx >= 0) {
            this.state.selectedIds = this.state.selectedIds.filter(id => id !== productId);
        } else {
            const product = this.state.products.find(p => p.id === productId);
            this.state.selectedIds = [...this.state.selectedIds, productId];
            // Auto-fill qty with 1 as default if not yet set
            if (this.state.qtys[productId] === undefined && product) {
                this.state.qtys = {
                    ...this.state.qtys,
                    [productId]: 1,
                };
            }
            if (this.state.prices[productId] === undefined && product) {
                this.state.prices = {
                    ...this.state.prices,
                    [productId]: product.list_price,
                };
            }
        }
    }

    /**
     * Update the qty to quote for a product.
     * @param {number} productId
     * @param {number} qty
     */
    onQtyChange(productId, qty) {
        this.state.qtys = { ...this.state.qtys, [productId]: qty };
    }

    /**
     * Update the unit price for a product.
     * @param {number} productId
     * @param {number} price
     */
    onPriceChange(productId, price) {
        this.state.prices = { ...this.state.prices, [productId]: price };
    }

    /**
     * Clear all selections.
     */
    clearSelection() {
        this.state.selectedIds = [];
    }

    // ── Computed ───────────────────────────────────────────────────────────

    /**
     * Whether all currently displayed products are selected.
     * @returns {boolean}
     */
    get allSelected() {
        return (
            this.state.products.length > 0 &&
            this.state.products.every(p => this.state.selectedIds.includes(p.id))
        );
    }

    /**
     * Compute summary statistics from the current product list.
     * @returns {{ inStock: number, outOfStock: number, lowStock: number, withIncoming: number }}
     */
    get stats() {
        const products = this.state.products;
        const threshold = products[0]?.low_stock_threshold ?? 5;
        return {
            inStock:     products.filter(p => p.actual_available > threshold).length,
            lowStock:    products.filter(p => p.actual_available > 0 && p.actual_available <= threshold).length,
            outOfStock:  products.filter(p => p.actual_available <= 0).length,
            withIncoming:products.filter(p => p.incoming_qty > 0).length,
        };
    }

    // ── Quotation Creation ─────────────────────────────────────────────────

    /**
     * Create a sale.order quotation from the selected products.
     * Opens the created quotation form via action service.
     */
    async createQuotation() {
        const lines = this.state.selectedIds
            .map(id => {
                const qty = this.state.qtys[id] || 0;
                if (qty <= 0) return null;
                return {
                    product_id: id,
                    qty: qty,
                    price: this.state.prices[id] ?? 0,
                };
            })
            .filter(Boolean);

        if (!lines.length) {
            this._showToast('error', _t('No Items'), _t('Please set qty > 0 for at least one product.'));
            return;
        }

        this.state.creating = true;
        try {
            const result = await this.orm.call(
                'stock.checker.helper', 'create_quotation', [],
                {
                    lines,
                    partner_id: this.state.selectedPartnerId || false,
                    partner_name: (!this.state.selectedPartnerId && this.state.partnerName)
                        ? this.state.partnerName
                        : false,
                }
            );

            if (result.error) {
                this._showToast('error', _t('Error'), result.error);
                return;
            }

            // Build toast message including partner info
            const partnerInfo = this.state.partnerName ? ` for ${this.state.partnerName}` : '';
            this._showToast(
                'success',
                _t('Quotation Created'),
                _t('%(name)s%(partner)s has been created.', {
                    name: result.name,
                    partner: partnerInfo,
                })
            );

            // Open created quotation
            await this.action.doAction({
                type: 'ir.actions.act_window',
                res_model: 'sale.order',
                res_id: result.sale_order_id,
                views: [[false, 'form']],
                target: 'current',
            });

            // Reset selection and partner fields
            this.state.selectedIds = [];
            this.state.qtys = {};
            this.state.prices = {};
            this.state.partnerCode = '';
            this.state.partnerName = '';
            this.state.selectedPartnerId = false;
            this.state.partnerResults = [];

        } catch (err) {
            this._showToast('error', _t('Error'), _t('Failed to create quotation.'));
            console.error('[StockChecker] create_quotation error:', err);
        } finally {
            this.state.creating = false;
        }
    }

    // ── Helpers ────────────────────────────────────────────────────────────

    /**
     * Save warehouse/location preferences for the current user.
     */
    async _savePreferences() {
        try {
            await this.orm.call(
                'stock.checker.helper', 'save_user_preferences', [],
                {
                    warehouse_id: this.state.selectedWarehouseId,
                    location_id: this.state.selectedLocationId,
                }
            );
        } catch (err) {
            // Non-critical, fail silently
        }
    }

    /**
     * Show a toast notification for a given duration.
     * @param {'success'|'error'|'info'} type
     * @param {string} title
     * @param {string} msg
     * @param {number} [duration=4000] - Auto-dismiss duration in ms
     */
    _showToast(type, title, msg, duration = 4000) {
        this.state.toast = { type, title, msg };
        if (this._toastTimer) clearTimeout(this._toastTimer);
        this._toastTimer = setTimeout(() => {
            this.state.toast = null;
        }, duration);
    }

    /**
     * Dismiss the current toast immediately.
     */
    clearToast() {
        this.state.toast = null;
        if (this._toastTimer) {
            clearTimeout(this._toastTimer);
            this._toastTimer = null;
        }
    }

    /**
     * Expose formatQty to the template.
     * @param {number} qty
     * @returns {string}
     */
    formatQty(qty) {
        return formatQty(qty);
    }
}

