.sc-chip-success strong { color: var(--sc-success); }
.sc-chip-warning strong { color: var(--sc-warning); }
.sc-chip-danger  strong { color: var(--sc-danger); }
.sc-chip-accent  strong { color: var(--sc-accent); }

/* ═══════════════════════════════════════════════════════════════
