this.state = useState({
    // Warehouse & location
    warehouses: [],
    locations: [],
    selectedWarehouseId: false,
    selectedLocationId: false,

    // Product data
    products: [],
    total: 0,
    offset: 0,
    limit: 50,

    // UI
    loading: false,
    creating: false,
    search: '',
    filterType: 'all',
    toast: null,

    // Stats (computed server-side across ALL products)
    stats: { in_stock: 0, low_stock: 0, out_of_stock: 0, with_incoming: 0 },

    // Selection
    selectedIds: [],
    qtys: {},      // { productId: qty }
    prices: {},    // { productId: price }

